// pubspec: flutter_riverpod: ^2.5.1
import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';

// ================= 1. Sync mutable state — NotifierProvider ==============
final counterProvider = NotifierProvider<CounterNotifier, int>(CounterNotifier.new);

class CounterNotifier extends Notifier<int> {
  @override
  int build() => 0;                      // initial state

  void increment() => state++;
  void reset() => state = 0;
}

// ================= 2. Async state — AsyncNotifierProvider.family =========
final userProvider = AsyncNotifierProvider.family<UserNotifier, User, int>(
  UserNotifier.new,
);

class UserNotifier extends FamilyAsyncNotifier<User, int> {
  @override
  Future<User> build(int id) async {
    // Riverpod caches by (provider + arg). Same id → same result reused.
    return _repo.fetchUser(id);
  }

  Future<void> refresh() async {
    state = const AsyncLoading();
    state = await AsyncValue.guard(() => _repo.fetchUser(arg));
  }

  UserRepository get _repo => ref.read(userRepoProvider);
}

// ================= 3. Pure DI — a Provider for the repository ============
final userRepoProvider = Provider<UserRepository>((ref) => UserRepository());

class User { const User(this.id, this.name); final int id; final String name; }
class UserRepository {
  Future<User> fetchUser(int id) async {
    await Future.delayed(const Duration(milliseconds: 400));
    return User(id, 'User $id');
  }
}

// ================= 4. UI — ConsumerWidget / ConsumerStatefulWidget =======
void main() => runApp(const ProviderScope(child: MaterialApp(home: HomePage())));

class HomePage extends ConsumerWidget {
  const HomePage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final count = ref.watch(counterProvider);
    final userAsync = ref.watch(userProvider(42));    // family with id=42

    return Scaffold(
      appBar: AppBar(title: const Text('Riverpod demo')),
      body: Column(
        children: [
          Text('Count: $count'),
          FilledButton(
            onPressed: () => ref.read(counterProvider.notifier).increment(),
            child: const Text('+1'),
          ),
          const Divider(),

          // AsyncValue.when — exhaustive, compiler-checked
          userAsync.when(
            loading: () => const CircularProgressIndicator(),
            error:   (e, s) => Text('error: $e'),
            data:    (u) => Text('Hi, ${u.name}'),
          ),
        ],
      ),
    );
  }
}

